    }

    public static function getOthersItems()
    {
        return [
            [
                'icon' => 'settings',
                'name' => 'Settings',
                'path' => '/settings',
            ],
        ];
    }

    public static function getMenuGroups()
    {
        return [
            [
                'title' => 'Menu',
                'items' => self::getMainNavItems()
            ],
            [
                'title' => 'Others',
                'items' => self::getOthersItems()
            ]
        ];
    }

    public static function isActive($path)
    {
        return request()->is(ltrim($path, '/'));
